def generate_signals(context):
    as_of = pd.to_datetime(context.as_of).strftime('%Y-%m-%d')
    allowed = set(getattr(context, 'symbols', []) or [])
    sig = SIGNALS.get(as_of, {})
    if allowed:
        return {s: float(w) for s, w in sig.items() if s in allowed}
    return {s: float(w) for s, w in sig.items()}
